starterCode.css:
body {
  display: grid;
  place-items: center;
  min-height: 100vh;
  background: #f4f7f5;
  font-family: system-ui, sans-serif;
}

form {
  display: grid;
  gap: 12px;
  width: min(360px, 92vw);
  padding: 24px;
  background: white;
  border-radius: 14px;
}

label {
  display: grid;
  gap: 4px;
  font-weight: 600;
}

/* Estiliza inputs, textarea y boton */
